sql:
SELECT prediction_id, home_goals, away_goals
FROM predictions
WHERE match_id = 987768;

SELECT SUM(stake) AS total_bets_placed
FROM betting_actions
WHERE match_id = 987768;

SELECT SUM(profit) AS total_winning_profit
FROM betting_actions
WHERE bet_result = 'win';

SELECT AVG(home_goals) AS average_home_goals
FROM predictions
JOIN betting_odds ON predictions.match_id = betting_odds.match_id;

SELECT user_id, SUM(profit) AS total_profit
FROM betting_actions
GROUP BY user_id;

SELECT AVG(total_bets_placed)
FROM users
WHERE total_bets_placed > 10;

external_knowledge:
- The 'top models' refer to the models with the highest average prediction accuracy; 
- The 'overall accuracy' is calculated as the average of the prediction accuracies derived from the settled bets;
- "Rank among each other" refers to the relative position of the models based on their overall accuracy, with the highest accuracy receiving the top rank.
